    "id": 22,
    "slug": "volunteers-discover-rare-space-weather-events-using-their-ears",
    "cat": "Física",
    "catCls": "fisica",
    "img": "https://assets.science.nasa.gov/content/dam/science/cds/citizen-science/highlights/2026/HARP_graphic.jpg/jcr:content/renditions/cq5dam.web.1280.1280.jpeg",
